    // PDF_TO_EXERCISE and SUPPORT_GENERATION use the lite model since
    // gemini-3.1-pro doesn't exist in this Google AI account. Lite is
    // sufficient for these conversion tasks.
    PDF_TO_EXERCISE: 'gemini-3.1-flash-lite-preview',
=======
    PDF_TO_EXERCISE: 'gemini-2.5-flash',
>>>>>>> origin/dev
    ANSWER_VALIDATION: 'gemini-3.1-pro',
    SUPPORT_GENERATION: 'gemini-3.1-flash-lite-preview',
    CONTENT_TRANSLATION: 'gemini-3.1-pro',
  },
  [LLMProviderType.OPENAI_COMPATIBLE]: {
    IMAGE_TO_EXERCISE: 'MiniMax-M2.1',
    EXERCISE_CHAT: 'MiniMax-M2.1',
    PDF_TO_EXERCISE: 'MiniMax-M2.1',
    ANSWER_VALIDATION: 'MiniMax-M2.1',
    SUPPORT_GENERATION: 'MiniMax-M2.1',
    CONTENT_TRANSLATION: 'MiniMax-M2.1',
  },
} as const

// ─────────────────────────────────────────────────────────────────────────────
// Runtime Override Support
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Get model name override from environment variables
 * Supports:
 * - LLM_MODEL_OVERRIDE_<MODEL_KEY> (e.g., LLM_MODEL_OVERRIDE_EXERCISE_CHAT)
 * - LLM_MODEL_OVERRIDE_DEFAULT (fallback for all models)
 */
export function getModelNameOverride(modelKey: AIModelKey): string | undefined {
  // Check specific model override first
  const specificOverride = process.env[`LLM_MODEL_OVERRIDE_${modelKey}`]
  if (specificOverride) {
    return specificOverride
  }

  // Check default override
  return process.env.LLM_MODEL_OVERRIDE_DEFAULT
}

/**
 * Check if any model override is configured
 */
export function isModelOverrideConfigured(): boolean {
  return (
    Object.keys(process.env).some((key) => key.startsWith('LLM_MODEL_OVERRIDE_')) ||
    process.env.LLM_MODEL_OVERRIDE_DEFAULT !== undefined
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Convenience Exports (backward compatibility)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * AI Models configuration - backward compatible export
 * Uses Gemini as the default provider for existing consumers
 *
 * @deprecated Use getProviderModelConfig() for provider-aware selection
 */
export const AI_MODELS: Record<AIModelKey, AIModel> = {
  IMAGE_TO_EXERCISE: {
    ...MODEL_REGISTRY.IMAGE_TO_EXERCISE,
    name: PROVIDER_MODEL_NAMES[LLMProviderType.GEMINI].IMAGE_TO_EXERCISE,
    modelKey: 'IMAGE_TO_EXERCISE',
  },
  EXERCISE_CHAT: {
    ...MODEL_REGISTRY.EXERCISE_CHAT,
    name: PROVIDER_MODEL_NAMES[LLMProviderType.GEMINI].EXERCISE_CHAT,
    modelKey: 'EXERCISE_CHAT',
  },
  PDF_TO_EXERCISE: {
    ...MODEL_REGISTRY.PDF_TO_EXERCISE,
    name: PROVIDER_MODEL_NAMES[LLMProviderType.GEMINI].PDF_TO_EXERCISE,
    modelKey: 'PDF_TO_EXERCISE',
  },
  ANSWER_VALIDATION: {
    ...MODEL_REGISTRY.ANSWER_VALIDATION,
    name: PROVIDER_MODEL_NAMES[LLMProviderType.GEMINI].ANSWER_VALIDATION,
    modelKey: 'ANSWER_VALIDATION',
  },
  SUPPORT_GENERATION: {
    ...MODEL_REGISTRY.SUPPORT_GENERATION,
    name: PROVIDER_MODEL_NAMES[LLMProviderType.GEMINI].SUPPORT_GENERATION,
    modelKey: 'SUPPORT_GENERATION',
  },
  CONTENT_TRANSLATION: {
    ...MODEL_REGISTRY.CONTENT_TRANSLATION,
    name: PROVIDER_MODEL_NAMES[LLMProviderType.GEMINI].CONTENT_TRANSLATION,
    modelKey: 'CONTENT_TRANSLATION',
  },
} as const

/**
 * Type for AI_MODELS values - preserved for backward compatibility
 */
export type AIModelConfig = AIModel

// ─────────────────────────────────────────────────────────────────────────────
// Helper Functions
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Get model registry entry for a given key
 * Useful for accessing provider-agnostic config
 */
export function getModelRegistryEntry(modelKey: AIModelKey): Omit<AIModel, 'name'> {
  return MODEL_REGISTRY[modelKey]
}

/**
 * Get provider-specific model name for a given key and provider
 */
export function getProviderModelName(providerType: LLMProviderType, modelKey: AIModelKey): string {
  return PROVIDER_MODEL_NAMES[providerType][modelKey]
}

/**
 * Check if a model supports a specific capability
 */
export function modelSupportsCapability(modelKey: AIModelKey, capability: string): boolean {
  return MODEL_REGISTRY[modelKey].capabilities?.includes(capability) ?? false
}

/**
 * Get all model keys that support a specific capability
 */
export function getModelsWithCapability(capability: string): AIModelKey[] {
  return (Object.keys(MODEL_REGISTRY) as AIModelKey[]).filter((key) =>
    MODEL_REGISTRY[key].capabilities?.includes(capability),
  )
}

/**
 * LLM Model Configuration Integration Tests
 *
 * Validates that model configurations are correctly set up for each provider.
 * These tests verify the configuration structure without making actual API calls.
 *
 * Run with:
 *   pnpm test:int -- tests/int/llm-model-reply-validation.int.spec.ts
 *
 * Prerequisites:
 *   - MongoDB container running (testcontainers) or USE_MONGO_SERVICE=true
 *
 * Note: Actual API calls are tested separately in manual tests or e2e tests
 * because they require proper server-side runtime configuration.
 */
import type { AIModelKey } from '@/infra/llm/models'
import {
  LLMProviderType,
  getProviderModelConfig,
  getProviderTypeFromEnv,
} from '@/infra/llm/providers/factory'
import { startMongoContainer, stopMongoContainer } from '@/infra/utils/test/mongodb-container'
import config from '@payload-config'
import { getPayload, type Payload } from 'payload'
import { afterAll, beforeAll, beforeEach, describe, expect, it } from 'vitest'

describe('LLM Model Configuration Validation', () => {
  let mongoUri: string
  let payload: Payload

  beforeAll(async () => {
    // Start MongoDB container for integration tests
    mongoUri = await startMongoContainer()
    process.env.DATABASE_URL = mongoUri
    process.env.PAYLOAD_SECRET = 'test-secret-key-for-integration-tests-only-minimum-32-chars'
    process.env.NEXT_PUBLIC_SERVER_URL = 'http://localhost:3000'
    process.env.DEFAULT_TENANT_SLUG = 'default'

    // Initialize Payload
    payload = await getPayload({ config })
  }, 180000)

  afterAll(async () => {
    // Close DB connection before stopping container
    if (payload?.db?.destroy) {
      await payload.db.destroy()
    }

    await stopMongoContainer()
  })

  describe('Model Configuration Structure', () => {
    it('should have valid AIModel structure for all models and providers', () => {
      const modelKeys: AIModelKey[] = ['EXERCISE_CHAT', 'IMAGE_TO_EXERCISE', 'PDF_TO_EXERCISE']
      const providers = [LLMProviderType.GEMINI, LLMProviderType.OPENAI_COMPATIBLE]

      for (const provider of providers) {
        for (const modelKey of modelKeys) {
          const modelConfig = getProviderModelConfig(provider, modelKey)

          // Validate required AIModel fields
          expect(modelConfig).toHaveProperty('name')
          expect(modelConfig).toHaveProperty('temperature')
          expect(modelConfig).toHaveProperty('maxOutputTokens')

          // Validate field types
          expect(typeof modelConfig.name).toBe('string')
          expect(modelConfig.name.length).toBeGreaterThan(0)
          expect(typeof modelConfig.temperature).toBe('number')
          expect(typeof modelConfig.maxOutputTokens).toBe('number')
        }
      }
    })

    it('should have correct model names for Gemini provider', () => {
      // EXERCISE_CHAT, PDF_TO_EXERCISE, SUPPORT_GENERATION use flash-lite
      // (pro doesn't exist in this account); IMAGE_TO_EXERCISE keeps pro.
      expect(getProviderModelConfig(LLMProviderType.GEMINI, 'EXERCISE_CHAT').name).toBe(
        'gemini-3.1-flash-lite-preview',
      )
      expect(getProviderModelConfig(LLMProviderType.GEMINI, 'IMAGE_TO_EXERCISE').name).toBe(
        'gemini-3.1-pro',
      )
      expect(getProviderModelConfig(LLMProviderType.GEMINI, 'PDF_TO_EXERCISE').name).toBe(
<<<<<<< HEAD
        'gemini-3.1-flash-lite-preview',
=======
        'gemini-2.5-flash',
>>>>>>> origin/dev
      )
    })

    it('should have correct model names for OpenAI-compatible provider', () => {
      // OpenAI-compatible uses MiniMax-M2.1 for all models
      expect(getProviderModelConfig(LLMProviderType.OPENAI_COMPATIBLE, 'EXERCISE_CHAT').name).toBe(
        'MiniMax-M2.1',
      )
      expect(
        getProviderModelConfig(LLMProviderType.OPENAI_COMPATIBLE, 'IMAGE_TO_EXERCISE').name,
      ).toBe('MiniMax-M2.1')
      expect(
        getProviderModelConfig(LLMProviderType.OPENAI_COMPATIBLE, 'PDF_TO_EXERCISE').name,
      ).toBe('MiniMax-M2.1')
    })

    it('should have appropriate temperature settings per model use case', () => {
      // EXERCISE_CHAT: Higher temperature (0.7) for creative/chat responses
      const chatConfig = getProviderModelConfig(LLMProviderType.GEMINI, 'EXERCISE_CHAT')
      expect(chatConfig.temperature).toBe(0.7)
      expect(chatConfig.temperature).toBeGreaterThan(0.5) // Should be relatively high for creativity

      // IMAGE_TO_EXERCISE: Lower temperature (0.2) for consistent extraction
      const imageConfig = getProviderModelConfig(LLMProviderType.GEMINI, 'IMAGE_TO_EXERCISE')
      expect(imageConfig.temperature).toBe(0.2)
      expect(imageConfig.temperature).toBeLessThan(0.5) // Should be lower for consistency

      // PDF_TO_EXERCISE: Low temperature (0.1) for accurate extraction
      const pdfConfig = getProviderModelConfig(LLMProviderType.GEMINI, 'PDF_TO_EXERCISE')
      expect(pdfConfig.temperature).toBe(0.1)
      expect(pdfConfig.temperature).toBeLessThan(0.3) // Should be lowest for accuracy
    })

    it('should have appropriate maxOutputTokens per model use case', () => {
      // EXERCISE_CHAT: Moderate tokens for chat responses (2048)
      const chatConfig = getProviderModelConfig(LLMProviderType.GEMINI, 'EXERCISE_CHAT')
      expect(chatConfig.maxOutputTokens).toBe(2048)
      expect(chatConfig.maxOutputTokens).toBeLessThan(8192)

      // IMAGE_TO_EXERCISE: High tokens for detailed extraction (8192)
      const imageConfig = getProviderModelConfig(LLMProviderType.GEMINI, 'IMAGE_TO_EXERCISE')
      expect(imageConfig.maxOutputTokens).toBe(8192)

      // PDF_TO_EXERCISE: High tokens for document extraction (32768)
      const pdfConfig = getProviderModelConfig(LLMProviderType.GEMINI, 'PDF_TO_EXERCISE')
      expect(pdfConfig.maxOutputTokens).toBe(32768)
    })

    it('should have temperature within valid range (0.0 - 2.0)', () => {
      const modelKeys: AIModelKey[] = ['EXERCISE_CHAT', 'IMAGE_TO_EXERCISE', 'PDF_TO_EXERCISE']
      const providers = [LLMProviderType.GEMINI, LLMProviderType.OPENAI_COMPATIBLE]

      for (const provider of providers) {
        for (const modelKey of modelKeys) {
          const modelConfig = getProviderModelConfig(provider, modelKey)
          expect(modelConfig.temperature).toBeGreaterThanOrEqual(0.0)
          expect(modelConfig.temperature).toBeLessThanOrEqual(2.0)
        }
      }
    })

    it('should have positive maxOutputTokens', () => {
      const modelKeys: AIModelKey[] = ['EXERCISE_CHAT', 'IMAGE_TO_EXERCISE', 'PDF_TO_EXERCISE']
      const providers = [LLMProviderType.GEMINI, LLMProviderType.OPENAI_COMPATIBLE]

      for (const provider of providers) {
        for (const modelKey of modelKeys) {
          const modelConfig = getProviderModelConfig(provider, modelKey)
          expect(modelConfig.maxOutputTokens).toBeGreaterThan(0)
        }
      }
    })
  })

  describe('Provider Model Name Getters', () => {
    it('should return correct model names via getProviderModelConfig', () => {
      // Gemini provider
      expect(getProviderModelConfig(LLMProviderType.GEMINI, 'EXERCISE_CHAT').name).toBe(
        'gemini-3.1-flash-lite-preview',
      )
      expect(getProviderModelConfig(LLMProviderType.GEMINI, 'IMAGE_TO_EXERCISE').name).toBe(
        'gemini-3.1-pro',
      )
      expect(getProviderModelConfig(LLMProviderType.GEMINI, 'PDF_TO_EXERCISE').name).toBe(
